mapper.select:
SELECT id, supplier_id as "supplierId", order_id as "orderId", state_id as "stateId", order_amount as "orderAmount", commission_amount as "commissionAmount", platform_fee as "platformFee", net_amount as "netAmount", currency, settlement_period_start as "settlementPeriodStart", settlement_period_end as "settlementPeriodEnd", disbursement_reference as "disbursementReference" FROM settlements
AND supplier_id = #{supplierId} AND state_id = #{stateId} AND order_id = #{orderId} AND currency = #{currency}
${orderby} ${pagination}

SELECT count(*) FROM settlements

    AND supplier_id = #{supplierId}
    AND state_id = #{stateId}
    AND order_id = #{orderId}

SELECT count(*) FROM settlements
WHERE supplier_id = #{supplierId}
AND state_id = #{stateId}

SELECT count(*) FROM settlements
WHERE state_id IN ('PENDING', 'CALCULATING', 'CALCULATED', 'APPROVED')
AND supplier_id = #{supplierId}

SELECT supplier_id as "supplierId", count(*) as "orderAmount", sum(net_amount) as "netAmount", sum(commission_amount) as "commissionAmount", sum(platform_fee) as "platformFee" FROM settlements
AND supplier_id = #{supplierId}
GROUP BY supplier_id

SELECT count(*) FROM settlements
WHERE supplier_id = #{supplierId}
AND state_id = #{stateId}
